/// <summary>
///    The <c>ETGAgreementTrackingPurchReportContract</c> class handles the parameters for the Agreement tracking report.
/// </summary>
[DataContractAttribute,SysOperationContractProcessing(classStr(ETGAgreementTrackingPurchReportUIBuilder))]
class ETGAgreementTrackingPurchReportContract implements SysOperationValidatable
{
    FromDate            fromDate;
    DateOnhand          PerDate;
    str                 etgCommodity;
    str                 etgSubCommodity;
    str                 etgVertical;
    str                 etgSubVertical;
    boolean             qty;

}

Method.Source:
public void initialize()
{
    fromDate        = dateNull();
    etgCommodity    = '';
    etgSubCommodity = '';
    etgVertical     = '';
    etgSubVertical  = '';
}

[
    DataMemberAttribute('fromDate'),
    SysOperationLabelAttribute(literalStr("@ETG_New:FromDate")),
    SysOperationDisplayOrderAttribute('1')
 ]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[
DataMemberAttribute('PerDate'),
SysOperationLabelAttribute(literalStr("@ETG_New:ToDate")),
SysOperationDisplayOrderAttribute('2')
]
public DateOnhand parmPerDate(DateOnhand _PerDate = PerDate)
{
    if (!_PerDate && !PerDate)
    {
        PerDate = systemDateGet();
    }
    else
    {
        PerDate = _PerDate;
    }
    return PerDate;
}

[
    DataMemberAttribute('etgVertical'),
    SysOperationLabelAttribute(literalStr("@ETG_New:Vertical")),
    SysOperationDisplayOrderAttribute('3')
]
public str parmETGVertical(str _etgVertical = etgVertical)
{
    etgVertical = _etgVertical;
    return etgVertical;
}

[
    DataMemberAttribute('etgSubVertical'),
    SysOperationLabelAttribute(literalStr("@ETG_New:SubVertical")),
    SysOperationDisplayOrderAttribute('4')
]
public str parmETGSubVertical(str _etgSubVertical = etgSubVertical)
{
    etgSubVertical = _etgSubVertical;
    return etgSubVertical;
}

[
    DataMemberAttribute('etgCommodity'),
    SysOperationLabelAttribute(literalStr("@ETG_New:ETGMainCommodity")),
    SysOperationDisplayOrderAttribute('5')
]
public str parmETGCommodity(str _etgCommodity = etgCommodity)
{
    etgCommodity = _etgCommodity;
    return etgCommodity;
}

[
    DataMemberAttribute('etgSubCommodity'),
    SysOperationLabelAttribute(literalStr("@ETG_New:ETGSubCommodity")),
    SysOperationDisplayOrderAttribute('6')
]
public str parmETGSubCommodity(str _etgSubCommodity = etgSubCommodity)
{
    etgSubCommodity = _etgSubCommodity;
    return etgSubCommodity;
}

[
    DataMemberAttribute('qty'),
    SysOperationLabelAttribute(literalStr("@ETG_New:QualitySpecs")),
     SysOperationDisplayOrderAttribute('7')
]
public boolean parmQty(boolean _qty = qty)
{
    qty = _qty;
    return qty;
}

public boolean validate()
{
    boolean ret = true;

    if (ret && !this.parmPerDate() && this.parmPerDate() == dateNull())
    {
        ret = checkFailed("@ETG_New:ToDateValidation");
    }

    if (ret && this.parmFromDate() && this.parmPerDate() && this.parmFromDate() > this.parmPerDate())
    {
        ret = checkFailed("@GLS64374");
    }

    return ret;
}
